import { realpathSync, statSync } from "node:fs";
import { relative } from "node:path";

import {
  annotateFile,
  type ElementInfo,
  type PropValue,
} from "../../modules/annotation/annotate-file.ts";
import { sourceVersionHash } from "../../modules/annotation/source-version.ts";
import { createFilter, type FilterPattern } from "@rollup/pluginutils";
import type { IncomingMessage, ServerResponse } from "node:http";
import type { Plugin, ResolvedConfig, ViteDevServer } from "vite";
import { computeTempoAnnotatedProps } from "./annotation-strategy.ts";

const DEFAULT_INCLUDE: FilterPattern = ["**/*.tsx", "**/*.jsx"];
const DEFAULT_EXCLUDE: FilterPattern = ["**/node_modules/**"];
const ROOT_META_NAME = "tempo-project-root";

function cleanModuleId(id: string): string {
  return id.replace(/[?#].*$/, "");
}

function resolveCanonicalRoot(root: string): string {
  try {
    return realpathSync.native(root);
  } catch {
    return root;
  }
}

function hasRootMetaTag(html: string): boolean {
  return /<meta[^>]+name=["']tempo-project-root["'][^>]*>/i.test(html);
}

/** Error payload captured from Vite's HMR error events or console interception. */
export type TempoViteError = {
  type: "compile" | "evaluation";
  message: string;
  stack?: string;
  file?: string;
  frame?: string;
  plugin?: string;
  loc?: { file?: string; line?: number; column?: number };
};

export type ComputeAnnotatedProps = (
  info: ElementInfo,
  filepath: string,
  modifiedtsMs: number,
) => Record<string, PropValue>;

export interface TempoAnnotateOptions {
  computeAnnotatedProps?: ComputeAnnotatedProps;
  include?: FilterPattern;
  exclude?: FilterPattern;
}

// ---------------------------------------------------------------------------
// Error tracking server — tracks per-module errors and broadcasts the
// highest-priority error (or null) to SSE clients.
//
// Vite's HMR operates per-module: a successful update for module A should not
// clear an unrelated compile error in module B.  We key errors by the file
// that caused them so that clears are scoped to the module that was fixed.
// ---------------------------------------------------------------------------

type SseClient = ServerResponse<IncomingMessage>;

export interface TempoErrorServer {
  /** The error currently broadcast to SSE clients (most recent across all modules). */
  readonly currentError: TempoViteError | null;
  clients: Set<SseClient>;
  setError(error: TempoViteError): void;
  /** Clear errors for modules present in the HMR update. */
  clearErrorForModules(updatedPaths: string[]): void;
  /** Clear all errors unconditionally (e.g. report-clear endpoint). */
  clearAll(): void;
}

function createErrorServer(): TempoErrorServer {
  // Per-module error map keyed by file path (or "unknown" for errors without a file)
  const errorsByFile = new Map<string, TempoViteError>();

  function getMostRecentError(): TempoViteError | null {
    if (errorsByFile.size === 0) return null;
    // Map iterates in insertion order; setError does delete+set to push to end,
    // so the last entry is the most recently set error
    let latest: TempoViteError | null = null;
    for (const err of errorsByFile.values()) latest = err;
    return latest;
  }

  function broadcastCurrentState(): void {
    const data = JSON.stringify(server.currentError);
    for (const client of server.clients) {
      client.write(`data: ${data}\n\n`);
    }
  }

  const server: TempoErrorServer = {
    get currentError(): TempoViteError | null {
      return getMostRecentError();
    },
    clients: new Set(),

    setError(error: TempoViteError) {
      const key = error.file ?? error.loc?.file ?? "unknown";
      // Delete + set to move to end of Map iteration order (most recent)
      errorsByFile.delete(key);
      errorsByFile.set(key, error);
      broadcastCurrentState();
    },

    clearErrorForModules(updatedPaths: string[]) {
      if (errorsByFile.size === 0) return;
      let changed = false;
      for (const errorKey of [...errorsByFile.keys()]) {
        // An error is cleared when the module that caused it appears in the
        // HMR update's path list.  We check with endsWith because Vite update
        // paths are root-relative while error file paths may be absolute.
        if (
          errorKey === "unknown" ||
          updatedPaths.some((p) => errorKey.endsWith(p) || p.endsWith(errorKey))
        ) {
          errorsByFile.delete(errorKey);
          changed = true;
        }
      }
      if (changed) broadcastCurrentState();
    },

    clearAll() {
      // Broadcast null even if already empty — runtime evaluation errors
      // (caught by the frame preload's console.error interception) are
      // forwarded as diagnostics without going through the SSE pipeline.
      // Broadcasting null ensures the frame preload receives a clear signal.
      errorsByFile.clear();
      broadcastCurrentState();
    },
  };
  return server;
}

function readBody(req: IncomingMessage): Promise<string> {
  return new Promise((resolve, reject) => {
    const chunks: Buffer[] = [];
    req.on("data", (chunk: Buffer) => chunks.push(chunk));
    req.on("end", () => resolve(Buffer.concat(chunks).toString()));
    req.on("error", reject);
  });
}

function handleErrorMiddleware(
  errorServer: TempoErrorServer,
  req: IncomingMessage,
  res: ServerResponse,
  next: () => void,
) {
  const url = req.url;
  if (!url?.startsWith("/__tempo/")) return next();

  if (url === "/__tempo/report-error" && req.method === "POST") {
    readBody(req).then((body) => {
      try {
        errorServer.setError(JSON.parse(body) as TempoViteError);
      } catch {
        // ignore malformed JSON
      }
      res.statusCode = 200;
      res.end("ok");
    });
    return;
  }

  if (url === "/__tempo/report-clear" && req.method === "POST") {
    errorServer.clearAll();
    res.statusCode = 200;
    res.end("ok");
    return;
  }

  // Allow CORS preflight for SSE endpoint (browser fetches from a different port)
  if (url === "/__tempo/errors" && req.method === "OPTIONS") {
    res.writeHead(204, {
      "Access-Control-Allow-Origin": "*",
      "Access-Control-Allow-Methods": "GET, OPTIONS",
      "Access-Control-Allow-Headers": "*",
    });
    res.end();
    return;
  }

  if (url === "/__tempo/errors" && req.method === "GET") {
    res.writeHead(200, {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
      "Access-Control-Allow-Origin": "*",
    });

    // Send current state immediately
    res.write(`data: ${JSON.stringify(errorServer.currentError)}\n\n`);
    errorServer.clients.add(res);

    req.on("close", () => {
      errorServer.clients.delete(res);
    });
    return;
  }

  next();
}

export function tempoVitePlugin(options: TempoAnnotateOptions = {}): Plugin {
  // The plugin is a complete no-op unless the TEMPO env var is set.
  // This lets users keep tempoVitePlugin() in their vite config permanently
  // while only paying for annotation when running via Tempo's start script
  // (which sets TEMPO=true).
  const enabled = !!process.env.TEMPO;

  const include =
    options.include === undefined ? DEFAULT_INCLUDE : options.include;
  const exclude =
    options.exclude === undefined ? DEFAULT_EXCLUDE : options.exclude;
  const filter = createFilter(include, exclude);

  let canonicalRoot = process.cwd();
  let command: ResolvedConfig["command"] = "serve";
  const errorServer = createErrorServer();

  return {
    name: "tempo-annotate",
    enforce: "pre",

    // Expose error server for testing
    _tempoErrorServer: errorServer,

    configResolved(resolvedConfig) {
      if (!enabled) return;

      command = resolvedConfig.command;
      canonicalRoot = resolveCanonicalRoot(resolvedConfig.root);
    },

    configureServer(server: ViteDevServer) {
      if (!enabled) return;
      server.middlewares.use((req, res, next) => {
        handleErrorMiddleware(errorServer, req, res, next);
      });

      // Intercept outgoing HMR messages to capture errors and clears
      // server-side, so we don't depend on client-side script execution
      // (which fails in contexts where import.meta.hot is unavailable,
      // e.g. Electron WebContentsViews).
      //
      // In Vite 7, error middleware calls environment.hot.send() which may
      // be a different wrapper than server.ws. Intercept both to ensure
      // errors are captured regardless of which path Vite uses.
      const interceptHmrSend = (target: { send: Function }) => {
        const orig = target.send.bind(target);
        target.send = ((...args: unknown[]) => {
          const payload = args[0];
          if (
            typeof payload === "object" &&
            payload !== null &&
            "type" in payload
          ) {
            const typed = payload as {
              type: string;
              err?: Record<string, unknown>;
            };
            if (typed.type === "error") {
              const err = typed.err;
              errorServer.setError({
                type: "compile",
                message: (err?.message as string) ?? "Unknown error",
                stack: err?.stack as string | undefined,
                file:
                  (err?.id as string) ?? (err?.loc as { file?: string })?.file,
                frame: err?.frame as string | undefined,
                plugin: err?.plugin as string | undefined,
                loc: err?.loc as
                  | { file?: string; line?: number; column?: number }
                  | undefined,
              });
            } else if (typed.type === "update") {
              const updates = (typed as { updates?: Array<{ path?: string }> })
                .updates;
              const paths =
                updates
                  ?.map((u) => u.path)
                  .filter((p): p is string => typeof p === "string") ?? [];
              errorServer.clearErrorForModules(paths);
            }
          }
          return (orig as Function)(...args);
        }) as typeof orig;
      };

      interceptHmrSend(server.ws as { send: Function });
      const clientHot = (server as any).environments?.client?.hot;
      if (clientHot && clientHot !== server.ws) {
        interceptHmrSend(clientHot as { send: Function });
      }
    },

    transformIndexHtml(html) {
      if (!enabled || command !== "serve") {
        return;
      }

      if (hasRootMetaTag(html)) {
        return;
      }

      return [
        {
          tag: "meta",
          attrs: {
            name: ROOT_META_NAME,
            content: canonicalRoot,
          },
          injectTo: "head" as const,
        },
      ];
    },

    transform(source, id) {
      if (!enabled || command === "build") {
        return null;
      }

      if (id.startsWith("\0")) {
        return null;
      }

      const cleanId = cleanModuleId(id);
      if (!filter(cleanId)) {
        return null;
      }

      try {
        const filepath = relative(canonicalRoot, cleanId);
        const modifiedtsMs = Math.trunc(statSync(cleanId).mtimeMs);
        // Hash the exact source being transformed once per file; every element
        // in this file carries the same version token.
        const sourceVersion = sourceVersionHash(source);

        const result = annotateFile(source, cleanId, (info) =>
          computeTempoAnnotatedProps({
            info,
            filepath,
            modifiedtsMs,
            sourceVersion,
            computeAnnotatedProps: options.computeAnnotatedProps,
          }),
        );

        if (result.elementsAnnotated === 0) {
          return null;
        }

        return {
          code: result.annotatedSource,
          map: null,
        };
      } catch {
        return null;
      }
    },
  } as Plugin & { _tempoErrorServer: TempoErrorServer };
}

/** @deprecated Use `tempoVitePlugin` instead. */
export const tempoAnnotate = tempoVitePlugin;

