import { parseSync, type JSXElement, type ParseResult } from 'oxc-parser';
import { getTagName, walk } from '@modules/file-parser';

export interface ElementInfo {
  element: JSXElement;
  /** e.g. "div", "Button", "Foo.Bar" */
  tagName: string;
}

/** Supported prop value types. `undefined` values are skipped. */
export type PropValue =
  | string
  | number
  | boolean
  | null
  | undefined
  | ((...args: unknown[]) => unknown)
  | object;

function formatPropValue(value: PropValue): string | null {
  if (value === undefined) return null;
  if (typeof value === 'function') return value.toString();
  return JSON.stringify(value);
}

function formatProps(props: Record<string, PropValue>): string {
  return Object.entries(props)
    .map(([key, value]) => {
      const formatted = formatPropValue(value);
      if (formatted === null) return null;
      return ` ${key}={${formatted}}`;
    })
    .filter((s): s is string => s !== null)
    .join('');
}

function getExistingAttributeNames(element: JSXElement): Set<string> {
  const names = new Set<string>();

  for (const attr of element.openingElement.attributes ?? []) {
    if (attr.type !== 'JSXAttribute') continue;
    names.add(getTagName(attr.name));
  }

  return names;
}

function removeExistingProps(
  props: Record<string, PropValue>,
  existingNames: Set<string>
): Record<string, PropValue> {
  return Object.fromEntries(
    Object.entries(props).filter(([key]) => !existingNames.has(key))
  );
}

export interface AnnotateFileResult {
  annotatedSource: string;
  elementsAnnotated: number;
  /** The oxc-parser result. Check `parseResult.errors` for any parse errors. */
  parseResult: ParseResult;
}

/** Tag names that represent React fragments and should not be annotated */
const FRAGMENT_TAG_NAMES = new Set(['Fragment', 'React.Fragment']);

/**
 * Annotates JSX elements in a source file by inserting additional props.
 *
 * Visits every JSXElement in source order and calls the handler to compute
 * props to insert. Props are inserted at the end of each opening tag.
 *
 * Fragments are skipped since they don't render DOM elements:
 * - JSX shorthand fragments (`<>...</>`) are a separate AST node type
 * - `React.Fragment` and `Fragment` are skipped by tag name
 */
export function annotateFile(
  source: string,
  filename: string,
  computeAnnotatedProps: (info: ElementInfo) => Record<string, PropValue>
): AnnotateFileResult {
  const parseResult = parseSync(filename, source);
  const insertions: { position: number; text: string }[] = [];

  // Walk the AST to find all JSXElement nodes
  // Uses our own walker instead of oxc-parser's Visitor (CJS/ESM interop issue in Electron)
  walk(parseResult.program, {
    JSXElement(node: unknown) {
      const element = node as JSXElement;
      const tagName = getTagName(element.openingElement.name);
      if (FRAGMENT_TAG_NAMES.has(tagName)) return;

      const props = removeExistingProps(
        computeAnnotatedProps({ element, tagName }),
        getExistingAttributeNames(element)
      );
      if (Object.keys(props).length === 0) return;

      const openingElement = element.openingElement;

      // Insert before ">" or "/>" at end of opening tag, skipping whitespace before "/>"
      let insertPos = openingElement.end - 1;
      if (openingElement.selfClosing) {
        insertPos--;
        while (insertPos > openingElement.start && /\s/.test(source[insertPos - 1]!)) {
          insertPos--;
        }
      }

      insertions.push({ position: insertPos, text: formatProps(props) });
    },
  });

  // Build result in a single pass using chunks (O(n) instead of O(n*m))
  insertions.sort((a, b) => a.position - b.position);

  const chunks: string[] = [];
  let lastPos = 0;
  for (const { position, text } of insertions) {
    chunks.push(source.slice(lastPos, position));
    chunks.push(text);
    lastPos = position;
  }
  chunks.push(source.slice(lastPos));

  return { annotatedSource: chunks.join(''), elementsAnnotated: insertions.length, parseResult };
}
