
/**
 * Annotation Utilities
 *
 * Helper functions for working with oxc-parser AST nodes.
 */

import type { JSXElementName, JSXMemberExpression } from 'oxc-parser';

/**
 * Extracts the tag name string from any JSXElementName variant.
 *
 * JSXElementName is a union of three types representing different JSX tag syntaxes:
 * - JSXIdentifier: `<button>` → "button", `<Button>` → "Button"
 * - JSXNamespacedName: `<svg:rect>` → "svg:rect" (rare, used in SVG/XML)
 * - JSXMemberExpression: `<Foo.Bar>` → "Foo.Bar", `<UI.Button.Primary>` → "UI.Button.Primary"
 */
export function getTagName(name: JSXElementName): string {
  switch (name.type) {
    case 'JSXIdentifier':
      return name.name;
    case 'JSXNamespacedName':
      return `${name.namespace.name}:${name.name.name}`;
    case 'JSXMemberExpression':
      return getJSXMemberExpressionName(name);
  }
}

/**
 * Recursively builds the dotted name string from a JSXMemberExpression.
 *
 * JSXMemberExpression represents dotted component names like `<Foo.Bar.Baz>`:
 * - object: either a JSXIdentifier or another JSXMemberExpression (for chaining)
 * - property: always a JSXIdentifier (the rightmost part)
 */
export function getJSXMemberExpressionName(node: JSXMemberExpression): string {
  const object = node.object.type === 'JSXIdentifier' ? node.object.name : getJSXMemberExpressionName(node.object);
  return `${object}.${node.property.name}`;
}
