import { parseSync, type ParserOptions } from 'oxc-parser';
// oxc-parser's browser build (src-js/wasm.js) does not re-export `visitorKeys`.
// Deep-import the generated keys table so this works in both Node and browser.
import visitorKeysDefault from 'oxc-parser/src-js/generated/visit/keys.js';

const visitorKeys = visitorKeysDefault as Record<string, readonly string[]>;
import {
  BindingKind,
  type Binding,
  type Range,
  type Reference,
  type Scope,
  type ScopeAnalysis,
  ScopeFlags,
  ScopeType,
} from './types';

type AnyNode = {
  type: string;
  start?: number;
  end?: number;
  [key: string]: any;
};

type AnalyzeOptions = {
  filename?: string;
  parserOptions?: ParserOptions;
};

type ScopeStackItem = {
  scopeId: number;
};

const ReferenceContext = {
  Value: 'value',
  Type: 'type',
  ValueAsType: 'value-as-type',
} as const;

type ReferenceContext =
  (typeof ReferenceContext)[keyof typeof ReferenceContext];

const DEFAULT_FILENAME = 'file.tsx';

export function analyzeScopes(source: string, options: AnalyzeOptions = {}): ScopeAnalysis {
  const filename = options.filename ?? DEFAULT_FILENAME;
  const parseResult = parseSync(filename, source, options.parserOptions ?? undefined);
  const program = parseResult.program as AnyNode;

  const scopes: Scope[] = [];
  const bindings: Binding[] = [];
  const references: Reference[] = [];

  const scopeIdByNode = new WeakMap<object, number>();

  const rootScopeId = createScope({
    scopes,
    type: ScopeType.Program,
    start: 0,
    end: source.length,
    parentId: null,
    flags: getProgramFlags(program),
  });

  scopeIdByNode.set(program, rootScopeId);

  const bindingBuilder = new ScopeBuilder({
    source,
    scopes,
    bindings,
    scopeIdByNode,
  });

  bindingBuilder.walkBindings(program);

  const referenceBuilder = new ReferenceBuilder({
    scopes,
    bindings,
    references,
    scopeIdByNode,
  });

  referenceBuilder.walkReferences(program);

  return {
    source,
    scopes,
    bindings,
    references,
  };
}

export function getReferenceAtPosition(
  analysis: ScopeAnalysis,
  position: number,
): Reference | null {
  let best: Reference | null = null;
  for (const ref of analysis.references) {
    if (position >= ref.start && position < ref.end) {
      if (!best || (ref.end - ref.start) < (best.end - best.start)) {
        best = ref;
      }
    }
  }
  return best;
}

export function getBindingForReference(
  analysis: ScopeAnalysis,
  reference: Reference,
): Binding | null {
  if (reference.bindingId == null) {
    return null;
  }
  return analysis.bindings[reference.bindingId] ?? null;
}

export function getValidRangesAtPosition(
  analysis: ScopeAnalysis,
  position: number,
): Range[] {
  const ref = getReferenceAtPosition(analysis, position);
  if (!ref) return [];
  return getValidRangesForReference(analysis, ref);
}

export function getValidRangesForReference(
  analysis: ScopeAnalysis,
  reference: Reference,
): Range[] {
  const binding = getBindingForReference(analysis, reference);
  if (!binding) return [];
  const baseRange = getBindingVisibilityRange(analysis, binding);
  const shadowed = getShadowedRanges(analysis, binding, baseRange);
  return subtractRanges(baseRange, shadowed);
}

export function getBindingVisibilityRange(
  analysis: ScopeAnalysis,
  binding: Binding,
): Range {
  const scope = analysis.scopes[binding.scopeId];
  const start = isBlockScopedBindingKind(binding.kind)
    ? binding.declStart
    : scope.start;
  return { start, end: scope.end };
}

function getShadowedRanges(
  analysis: ScopeAnalysis,
  binding: Binding,
  baseRange: Range,
): Range[] {
  const rootScope = analysis.scopes[binding.scopeId];
  const ranges: Range[] = [];
  const stack = [...rootScope.childIds];
  const useTypeBindings = usesTypeBindingsForShadowing(binding.kind);

  while (stack.length) {
    const scopeId = stack.pop() as number;
    const scope = analysis.scopes[scopeId];
    const shadowBindingId = useTypeBindings
      ? scope.typeBindings.get(binding.name)
      : scope.bindings.get(binding.name);

    if (shadowBindingId != null && shadowBindingId !== binding.id) {
      ranges.push({ start: scope.start, end: scope.end });
      continue;
    }

    stack.push(...scope.childIds);
  }

  return ranges
    .map((range) => clampRange(range, baseRange))
    .filter((range): range is Range => range !== null);
}

function clampRange(range: Range, base: Range): Range | null {
  const start = Math.max(range.start, base.start);
  const end = Math.min(range.end, base.end);
  if (start >= end) return null;
  return { start, end };
}

function subtractRanges(base: Range, exclusions: Range[]): Range[] {
  if (!exclusions.length) return [base];
  const normalized = normalizeRanges(exclusions);
  let current: Range[] = [base];

  for (const ex of normalized) {
    const next: Range[] = [];
    for (const range of current) {
      next.push(...subtractOne(range, ex));
    }
    current = next;
    if (!current.length) break;
  }

  return current;
}

function subtractOne(range: Range, exclude: Range): Range[] {
  if (exclude.end <= range.start || exclude.start >= range.end) {
    return [range];
  }

  const result: Range[] = [];
  if (exclude.start > range.start) {
    result.push({ start: range.start, end: Math.min(exclude.start, range.end) });
  }
  if (exclude.end < range.end) {
    result.push({ start: Math.max(exclude.end, range.start), end: range.end });
  }
  return result;
}

function normalizeRanges(ranges: Range[]): Range[] {
  const sorted = [...ranges].sort((a, b) => a.start - b.start);
  const result: Range[] = [];

  for (const range of sorted) {
    const last = result[result.length - 1];
    if (!last || range.start > last.end) {
      result.push({ ...range });
    } else {
      last.end = Math.max(last.end, range.end);
    }
  }

  return result;
}

function isNode(value: unknown): value is AnyNode {
  return Boolean(value && typeof value === 'object' && (value as AnyNode).type);
}

function getParamList(params: AnyNode | AnyNode[] | null | undefined): AnyNode[] {
  if (!params) return [];
  if (Array.isArray(params)) return params;
  if (Array.isArray(params.params)) return params.params;
  if (Array.isArray(params.items)) return params.items;
  return [];
}

function getProgramFlags(program: AnyNode): ScopeFlags {
  const sourceType = program.sourceType ?? program.source_type ?? 'module';
  let flags = ScopeFlags.Top;
  if (sourceType === 'module') {
    flags |= ScopeFlags.Module | ScopeFlags.StrictMode;
  }
  if (hasUseStrictDirective(program)) {
    flags |= ScopeFlags.StrictMode;
  }
  return flags;
}

function hasUseStrictDirective(container: AnyNode | null | undefined): boolean {
  if (!container) return false;
  const directives = container.directives;
  if (Array.isArray(directives)) {
    for (const directive of directives) {
      if (getDirectiveText(directive) === 'use strict') {
        return true;
      }
    }
  }

  const statements =
    container.body ??
    container.statements ??
    container.body?.body ??
    container.body?.statements;
  if (Array.isArray(statements)) {
    for (const stmt of statements) {
      if (!stmt) continue;
      const directiveText = getDirectiveText(stmt);
      if (directiveText === 'use strict') {
        return true;
      }
      if (directiveText == null) {
        break;
      }
    }
  }

  return false;
}

function getDirectiveText(node: AnyNode | null | undefined): string | null {
  if (!node) return null;
  if (typeof node.directive === 'string') {
    return node.directive;
  }
  const expr = node.expression ?? node;
  if (expr?.type === 'StringLiteral' || expr?.type === 'Literal') {
    const value = expr.value ?? expr.rawValue ?? expr.raw;
    if (typeof value === 'string') return value;
  }
  return null;
}

function isStrictScope(node: AnyNode, type: ScopeType): boolean {
  if (type === ScopeType.Class) return true;
  if (type === ScopeType.Function) {
    return hasUseStrictDirective(node.body);
  }
  if (type === ScopeType.TsModule) {
    return hasUseStrictDirective(node.body);
  }
  return false;
}

function shouldAddToValueBindings(kind: BindingKind): boolean {
  switch (kind) {
    case BindingKind.Var:
    case BindingKind.Let:
    case BindingKind.Const:
    case BindingKind.Function:
    case BindingKind.Class:
    case BindingKind.Param:
    case BindingKind.Import:
    case BindingKind.Enum:
    case BindingKind.EnumMember:
    case BindingKind.Namespace:
      return true;
    default:
      return false;
  }
}

function shouldAddToTypeBindings(kind: BindingKind): boolean {
  switch (kind) {
    case BindingKind.TypeImport:
    case BindingKind.TypeAlias:
    case BindingKind.Interface:
    case BindingKind.TypeParam:
    case BindingKind.Class:
    case BindingKind.Enum:
    case BindingKind.EnumMember:
    case BindingKind.Namespace:
    case BindingKind.Import:
      return true;
    default:
      return false;
  }
}

function isBlockScopedBindingKind(kind: BindingKind): boolean {
  return (
    kind === BindingKind.Let ||
    kind === BindingKind.Const ||
    kind === BindingKind.Class ||
    kind === BindingKind.EnumMember
  );
}

function usesTypeBindingsForShadowing(kind: BindingKind): boolean {
  return (
    kind === BindingKind.TypeImport ||
    kind === BindingKind.TypeAlias ||
    kind === BindingKind.Interface ||
    kind === BindingKind.TypeParam
  );
}

function canReferenceAsType(kind: BindingKind): boolean {
  return (
    kind === BindingKind.TypeImport ||
    kind === BindingKind.TypeAlias ||
    kind === BindingKind.Interface ||
    kind === BindingKind.TypeParam ||
    kind === BindingKind.Class ||
    kind === BindingKind.Enum ||
    kind === BindingKind.EnumMember ||
    kind === BindingKind.Namespace ||
    kind === BindingKind.Import
  );
}

function canReferenceAsValueAsType(kind: BindingKind): boolean {
  return kind === BindingKind.TypeImport || shouldAddToValueBindings(kind);
}

class ScopeBuilder {
  private source: string;
  private scopes: Scope[];
  private bindings: Binding[];
  private scopeIdByNode: WeakMap<object, number>;
  private scopeStack: ScopeStackItem[] = [];

  constructor({
    source,
    scopes,
    bindings,
    scopeIdByNode,
  }: {
    source: string;
    scopes: Scope[];
    bindings: Binding[];
    scopeIdByNode: WeakMap<object, number>;
  }) {
    this.source = source;
    this.scopes = scopes;
    this.bindings = bindings;
    this.scopeIdByNode = scopeIdByNode;
    this.scopeStack.push({ scopeId: 0 });
  }

  walkBindings(node: AnyNode, ancestors: AnyNode[] = []): void {
    if (!node) return;
    switch (node.type) {
      case 'Program':
        this.registerScope(node, 0);
        this.walkChildren(node, ancestors);
        return;
      case 'BlockStatement':
        this.withScope(node, ScopeType.Block, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'FunctionDeclaration':
      case 'TSDeclareFunction':
        // `declare function f(...)` is a TSDeclareFunction — the same shape as
        // a FunctionDeclaration minus the body. Treating the two together
        // means ambient function declarations still bind their names at the
        // current scope and their parameters inside a function scope, so
        // downstream resolution behaves identically to the non-ambient form.
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Function, node.id);
        }
        this.withScope(node, ScopeType.Function, () => {
          const params = getParamList(node.params);
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.declareParams(params);
          this.walkParams(params, ancestors);
          if (node.body) {
            this.walkNode(node.body, ancestors);
          }
        });
        return;
      case 'FunctionExpression':
        this.withScope(node, ScopeType.Function, () => {
          if (node.id?.name) {
            this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Function, node.id);
          }
          const params = getParamList(node.params);
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.declareParams(params);
          this.walkParams(params, ancestors);
          this.walkNode(node.body, ancestors);
        });
        return;
      case 'ArrowFunctionExpression':
        this.withScope(node, ScopeType.Function, () => {
          const params = getParamList(node.params);
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.declareParams(params);
          this.walkParams(params, ancestors);
          if (node.body) {
            this.walkNode(node.body, ancestors);
          }
        });
        return;
      case 'VariableDeclaration':
        this.handleVariableDeclaration(node, ancestors);
        return;
      case 'ClassDeclaration':
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Class, node.id);
        }
        this.withScope(node, ScopeType.Class, () => {
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.walkNode(node.body, ancestors);
        });
        return;
      case 'ClassExpression':
        this.withScope(node, ScopeType.Class, () => {
          if (node.id?.name) {
            this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Class, node.id);
          }
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.walkNode(node.body, ancestors);
        });
        return;
      case 'StaticBlock':
        this.withScope(node, ScopeType.ClassStaticBlock, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'CatchClause':
        this.withScope(node, ScopeType.Catch, () => {
          if (node.param) {
            this.declarePattern(node.param, BindingKind.Param);
            this.walkPatternExpressions(node.param, ancestors);
          }
          this.walkNode(node.body, ancestors);
        });
        return;
      case 'ForStatement':
      case 'ForInStatement':
      case 'ForOfStatement':
        this.withScope(node, ScopeType.For, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'SwitchStatement':
        this.withScope(node, ScopeType.Switch, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'ImportDeclaration':
        this.handleImportDeclaration(node);
        return;
      case 'TSImportEqualsDeclaration':
        this.handleImportEqualsDeclaration(node);
        return;
      case 'TSModuleDeclaration':
        this.handleTsModuleDeclaration(node, ancestors);
        return;
      case 'TSGlobalDeclaration':
        this.withScope(node, ScopeType.TsModule, () => {
          if (node.body) {
            this.walkNode(node.body, ancestors);
          }
        });
        return;
      case 'TSTypeAliasDeclaration':
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.TypeAlias, node.id);
        }
        this.withScope(node, ScopeType.Type, () => {
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          this.walkNode(node.typeAnnotation ?? node.type_annotation, ancestors);
        });
        return;
      case 'TSInterfaceDeclaration':
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Interface, node.id);
        }
        this.withScope(node, ScopeType.Type, () => {
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          if (node.extends) {
            for (const heritage of node.extends) {
              this.walkNode(heritage, ancestors);
            }
          }
          if (node.body) {
            this.walkNode(node.body, ancestors);
          }
        });
        return;
      case 'TSEnumDeclaration':
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.Enum, node.id);
        }
        if (node.body) {
          this.walkNode(node.body, ancestors);
        }
        return;
      case 'TSEnumBody':
        this.withScope(node, ScopeType.Enum, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'TSEnumMember':
        if (node.id?.name) {
          this.declareBinding(this.currentScopeId(), node.id.name, BindingKind.EnumMember, node.id);
        }
        if (node.initializer) {
          this.walkNode(node.initializer, ancestors);
        }
        return;
      case 'TSTypeParameter':
        if (node.name?.name) {
          this.declareBinding(this.currentScopeId(), node.name.name, BindingKind.TypeParam, node.name);
        }
        if (node.constraint) {
          this.walkNode(node.constraint, ancestors);
        }
        if (node.default) {
          this.walkNode(node.default, ancestors);
        }
        return;
      case 'TSTypeParameterDeclaration':
        for (const param of node.params ?? []) {
          this.walkNode(param, ancestors);
        }
        return;
      case 'TSMappedType':
        this.withScope(node, ScopeType.Type, () => {
          if (node.key?.name) {
            this.declareBinding(this.currentScopeId(), node.key.name, BindingKind.TypeParam, node.key);
          }
          this.walkNode(node.constraint, ancestors);
          if (node.nameType ?? node.name_type) {
            this.walkNode(node.nameType ?? node.name_type, ancestors);
          }
          if (node.typeAnnotation ?? node.type_annotation) {
            this.walkNode(node.typeAnnotation ?? node.type_annotation, ancestors);
          }
        });
        return;
      case 'TSConditionalType':
        if (node.checkType ?? node.check_type) {
          this.walkNode(node.checkType ?? node.check_type, ancestors);
        }
        this.withScope(node, ScopeType.TsConditional, () => {
          if (node.extendsType ?? node.extends_type) {
            this.walkNode(node.extendsType ?? node.extends_type, ancestors);
          }
          if (node.trueType ?? node.true_type) {
            this.walkNode(node.trueType ?? node.true_type, ancestors);
          }
        });
        if (node.falseType ?? node.false_type) {
          this.walkNode(node.falseType ?? node.false_type, ancestors);
        }
        return;
      case 'TSFunctionType':
      case 'TSConstructorType':
      case 'TSCallSignatureDeclaration':
      case 'TSMethodSignature':
      case 'TSConstructSignatureDeclaration':
        this.withScope(node, ScopeType.Type, () => {
          this.declareTypeParameters(node.typeParameters ?? node.type_parameters, ancestors);
          const params = getParamList(node.params);
          this.declareParams(params);
          this.walkParams(params, ancestors);
          if (node.returnType ?? node.return_type) {
            this.walkNode(node.returnType ?? node.return_type, ancestors);
          }
        });
        return;
      default:
        this.walkChildren(node, ancestors);
    }
  }

  private currentScopeId(): number {
    return this.scopeStack[this.scopeStack.length - 1]?.scopeId ?? 0;
  }

  private withScope(node: AnyNode, type: ScopeType, fn: () => void): void {
    const parentScopeId = this.currentScopeId();
    const parentScope = this.scopes[parentScopeId];
    let flags = getScopeFlags(type, parentScope.flags);
    if (isStrictScope(node, type)) {
      flags |= ScopeFlags.StrictMode;
    }
    flags = inheritStrictMode(flags, parentScope.flags);
    const start = getScopeStart(node, type, this.source);
    const end = getScopeEnd(node, type, this.source);
    const scopeId = createScope({
      scopes: this.scopes,
      type,
      start,
      end,
      parentId: parentScopeId,
      flags,
    });
    this.registerScope(node, scopeId);
    if (type === ScopeType.Block && parentScope.type === ScopeType.Catch) {
      this.moveBindingsToChild(parentScopeId, scopeId);
    }
    this.scopeStack.push({ scopeId });
    fn();
    this.scopeStack.pop();
  }

  private registerScope(node: AnyNode, scopeId: number): void {
    if (node && typeof node === 'object') {
      this.scopeIdByNode.set(node, scopeId);
    }
  }

  private moveBindingsToChild(parentScopeId: number, childScopeId: number): void {
    const parentScope = this.scopes[parentScopeId];
    if (!parentScope.bindings.size) return;
    const childScope = this.scopes[childScopeId];
    for (const [name, bindingId] of parentScope.bindings.entries()) {
      childScope.bindings.set(name, bindingId);
      const binding = this.bindings[bindingId];
      if (binding) {
        binding.scopeId = childScopeId;
      }
    }
    parentScope.bindings.clear();
  }

  private declareBinding(scopeId: number, name: string, kind: BindingKind, node: AnyNode): number {
    const scope = this.scopes[scopeId];
    const addValue = shouldAddToValueBindings(kind);
    const addType = shouldAddToTypeBindings(kind);
    if (addValue) {
      const existingValue = scope.bindings.get(name);
      if (existingValue != null) {
        if (kind === BindingKind.Var || kind === BindingKind.Function) {
          return existingValue;
        }
        return existingValue;
      }
    } else if (addType) {
      const existingType = scope.typeBindings.get(name);
      if (existingType != null) {
        return existingType;
      }
    }
    const binding: Binding = {
      id: this.bindings.length,
      name,
      kind,
      declStart: node.start ?? 0,
      declEnd: node.end ?? (node.start ?? 0),
      scopeId,
    };
    this.bindings.push(binding);
    if (addValue) {
      scope.bindings.set(name, binding.id);
    }
    if (addType && !scope.typeBindings.has(name)) {
      scope.typeBindings.set(name, binding.id);
    }
    return binding.id;
  }

  private declareParams(params: AnyNode[]): void {
    for (const param of params) {
      this.declarePattern(param, BindingKind.Param);
    }
  }

  private declareTypeParameters(typeParameters: AnyNode | null | undefined, ancestors: AnyNode[]): void {
    if (!typeParameters) return;
    const params = typeParameters.params ?? typeParameters.parameters;
    const list = Array.isArray(params)
      ? params
      : Array.isArray(typeParameters.items)
        ? typeParameters.items
        : Array.isArray(typeParameters)
          ? typeParameters
          : [];
    for (const param of list) {
      this.walkNode(param, ancestors);
    }
  }

  private declarePattern(pattern: AnyNode, kind: BindingKind): void {
    const identifiers: AnyNode[] = [];
    collectBindingIdentifiers(pattern, identifiers);
    for (const ident of identifiers) {
      if (ident?.name) {
        this.declareBinding(this.currentScopeId(), ident.name, kind, ident);
      }
    }
  }

  private handleVariableDeclaration(node: AnyNode, ancestors: AnyNode[]): void {
    const kind = node.kind;
    const bindingKind = kind === 'var' ? BindingKind.Var : kind === 'let' ? BindingKind.Let : BindingKind.Const;
    for (const decl of node.declarations ?? []) {
      if (!decl) continue;
      const scopeId =
        bindingKind === BindingKind.Var
          ? this.findVarScopeId()
          : this.currentScopeId();
      const identifiers: AnyNode[] = [];
      collectBindingIdentifiers(decl.id, identifiers);
      for (const ident of identifiers) {
        if (ident?.name) {
          this.declareBinding(scopeId, ident.name, bindingKind, ident);
        }
      }
      if (decl.id) {
        this.walkPatternExpressions(decl.id, ancestors);
      }
      if (decl.init) {
        this.walkNode(decl.init, ancestors);
      }
    }
  }

  private handleImportDeclaration(node: AnyNode): void {
    const rootScopeId = 0;
    const declarationKind =
      (node.importKind ?? node.import_kind) === 'type'
        ? BindingKind.TypeImport
        : BindingKind.Import;
    for (const spec of node.specifiers ?? []) {
      const local = spec?.local;
      if (!local?.name) continue;
      let kind = declarationKind;
      if (spec?.type === 'ImportSpecifier') {
        const specKind = spec.importKind ?? spec.import_kind;
        if (declarationKind === BindingKind.Import && specKind === 'type') {
          kind = BindingKind.TypeImport;
        }
      }
      this.declareBinding(rootScopeId, local.name, kind, local);
    }
  }

  private handleImportEqualsDeclaration(node: AnyNode): void {
    const kind =
      (node.importKind ?? node.import_kind) === 'type'
        ? BindingKind.TypeImport
        : BindingKind.Import;
    if (node.id?.name) {
      this.declareBinding(this.currentScopeId(), node.id.name, kind, node.id);
    }
  }

  private handleTsModuleDeclaration(node: AnyNode, ancestors: AnyNode[]): void {
    const id = node.id;
    if (id?.type === 'Identifier' && id.name) {
      this.declareBinding(this.currentScopeId(), id.name, BindingKind.Namespace, id);
    }
    this.withScope(node, ScopeType.TsModule, () => {
      if (node.body) {
        this.walkNode(node.body, ancestors);
      }
    });
  }

  private walkParams(params: AnyNode[], ancestors: AnyNode[]): void {
    for (const param of params) {
      this.walkPatternExpressions(param, ancestors);
    }
  }

  private walkPatternExpressions(pattern: AnyNode, ancestors: AnyNode[]): void {
    if (!pattern) return;
    if (pattern.type === 'TSParameterProperty' && pattern.parameter) {
      this.walkPatternExpressions(pattern.parameter, ancestors.concat(pattern));
      return;
    }
    if (pattern.typeAnnotation) {
      this.walkNode(pattern.typeAnnotation, ancestors.concat(pattern));
    }
    switch (pattern.type) {
      case 'Identifier':
        return;
      case 'RestElement':
        this.walkPatternExpressions(pattern.argument, ancestors);
        return;
      case 'AssignmentPattern':
        this.walkPatternExpressions(pattern.left, ancestors);
        if (pattern.right) {
          this.walkNode(pattern.right, ancestors);
        }
        return;
      case 'ArrayPattern':
        for (const element of pattern.elements ?? []) {
          if (element) {
            this.walkPatternExpressions(element, ancestors);
          }
        }
        return;
      case 'ObjectPattern':
        for (const prop of pattern.properties ?? []) {
          if (!prop) continue;
          if (prop.type === 'Property') {
            if (prop.computed && prop.key) {
              this.walkNode(prop.key, ancestors);
            }
            if (prop.value) {
              this.walkPatternExpressions(prop.value, ancestors);
            }
          } else if (prop.type === 'RestElement') {
            this.walkPatternExpressions(prop.argument, ancestors);
          }
        }
        return;
      default:
        this.walkNode(pattern, ancestors);
    }
  }

  private findVarScopeId(): number {
    for (let i = this.scopeStack.length - 1; i >= 0; i -= 1) {
      const scope = this.scopes[this.scopeStack[i].scopeId];
      if (
        scope.type === ScopeType.Function ||
        scope.type === ScopeType.Program ||
        scope.type === ScopeType.ClassStaticBlock ||
        scope.type === ScopeType.TsModule
      ) {
        return scope.id;
      }
    }
    return 0;
  }

  private walkNode(node: AnyNode, ancestors: AnyNode[]): void {
    if (!node) return;
    this.walkBindings(node, ancestors.concat(node));
  }

  private walkChildren(node: AnyNode, ancestors: AnyNode[]): void {
    const keys = visitorKeys[node.type] ?? [];
    for (const key of keys) {
      const value = node[key];
      if (Array.isArray(value)) {
        for (const child of value) {
          if (isNode(child)) {
            this.walkBindings(child, ancestors.concat(node));
          }
        }
      } else if (isNode(value)) {
        this.walkBindings(value, ancestors.concat(node));
      }
    }
  }
}

class ReferenceBuilder {
  private scopes: Scope[];
  private bindings: Binding[];
  private references: Reference[];
  private scopeIdByNode: WeakMap<object, number>;
  private scopeStack: ScopeStackItem[] = [];
  private contextStack: ReferenceContext[] = [ReferenceContext.Value];

  constructor({
    scopes,
    bindings,
    references,
    scopeIdByNode,
  }: {
    scopes: Scope[];
    bindings: Binding[];
    references: Reference[];
    scopeIdByNode: WeakMap<object, number>;
  }) {
    this.scopes = scopes;
    this.bindings = bindings;
    this.references = references;
    this.scopeIdByNode = scopeIdByNode;
    this.scopeStack.push({ scopeId: 0 });
  }

  walkReferences(node: AnyNode, ancestors: AnyNode[] = []): void {
    if (!node) return;
    switch (node.type) {
      case 'Program':
      case 'BlockStatement':
      case 'ForStatement':
      case 'ForInStatement':
      case 'ForOfStatement':
      case 'SwitchStatement':
        this.withScope(node, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'FunctionDeclaration':
      case 'FunctionExpression':
      case 'ArrowFunctionExpression':
      case 'TSDeclareFunction':
      case 'TSEmptyBodyFunctionExpression':
        // TSDeclareFunction covers `declare function f(...)` and function
        // overload signatures; TSEmptyBodyFunctionExpression is the body-less
        // signature used by abstract methods. Both share function-shaped
        // scoping of params and need references inside their type annotations
        // and predicates to resolve against the function's own scope.
        this.withScope(node, () => {
          const params = getParamList(node.params);
          const typeParameters = node.typeParameters ?? node.type_parameters;
          const returnType = node.returnType ?? node.return_type;
          this.withTypeContext(() => {
            if (typeParameters) {
              this.walkReferences(typeParameters, ancestors.concat(node));
            }
            if (returnType) {
              this.walkReferences(returnType, ancestors.concat(node));
            }
          });
          for (const param of params) {
            this.walkPatternReferences(param, ancestors.concat(node));
          }
          if (node.body) {
            this.walkReferences(node.body, ancestors.concat(node));
          }
        });
        return;
      case 'CatchClause':
        this.withScope(node, () => {
          if (node.param) {
            this.walkPatternReferences(node.param, ancestors.concat(node));
          }
          if (node.body) {
            this.walkReferences(node.body, ancestors.concat(node));
          }
        });
        return;
      case 'ClassDeclaration':
      case 'ClassExpression':
        // Decorators evaluate in the enclosing scope (they run at class-definition
        // time), so walk them before entering the class scope.
        this.walkDecorators(node, ancestors);
        this.withScope(node, () => {
          if (node.superClass) {
            this.walkReferences(node.superClass, ancestors.concat(node));
          }
          const typeParameters = node.typeParameters ?? node.type_parameters;
          const superTypeArguments =
            node.superTypeArguments ??
            node.super_type_arguments ??
            node.superTypeParameters ??
            node.super_type_parameters;
          if (typeParameters) {
            this.withTypeContext(() => {
              this.walkReferences(typeParameters, ancestors.concat(node));
            });
          }
          if (superTypeArguments) {
            this.withTypeContext(() => {
              this.walkReferences(superTypeArguments, ancestors.concat(node));
            });
          }
          if (node.implements) {
            this.withTypeContext(() => {
              for (const impl of node.implements ?? []) {
                this.walkReferences(impl, ancestors.concat(node));
              }
            });
          }
          if (node.body) {
            this.walkReferences(node.body, ancestors.concat(node));
          }
        });
        return;
      case 'StaticBlock':
        this.withScope(node, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'VariableDeclarator':
        if (node.id) {
          this.walkPatternReferences(node.id, ancestors);
        }
        if (node.init) {
          this.walkReferences(node.init, ancestors.concat(node));
        }
        return;
      case 'ImportDeclaration':
        return;
      case 'ExportNamedDeclaration':
        // Walk the optional inline declaration (e.g. `export const x = 1`).
        // Specifiers come in two flavors:
        //   - `export { foo }` / `export { foo as bar }` (no `source`) — the
        //     `local` Identifier is a real reference to a local binding; the
        //     `exported` alias is external-only and must NOT count as a
        //     reference. In shorthand form the two point to the same node, so
        //     walking only `local` also prevents double-counting.
        //   - `export { foo } from 'm'` (with `source`) — neither side refers
        //     to a local binding; they're names on the re-exported module.
        if (node.declaration) {
          this.walkReferences(node.declaration, ancestors.concat(node));
        }
        if (!node.source) {
          for (const spec of node.specifiers ?? []) {
            if (spec?.local) {
              this.walkReferences(spec.local, ancestors.concat(node, spec));
            }
          }
        }
        return;
      case 'ExportAllDeclaration':
        // `export * from 'm'` and `export * as ns from 'm'` never reference
        // local bindings — the alias in the latter is an external name only.
        return;
      case 'ExportDefaultDeclaration':
        if (node.declaration) {
          this.walkReferences(node.declaration, ancestors.concat(node));
        }
        return;
      case 'MetaProperty':
        // `import.meta` / `new.target` — both children are syntactic keyword
        // tokens, not user identifiers, so there are no references to emit.
        return;
      case 'TSImportEqualsDeclaration':
        if (node.moduleReference ?? node.module_reference) {
          this.walkReferences(node.moduleReference ?? node.module_reference, ancestors.concat(node));
        }
        return;
      case 'TSModuleDeclaration':
      case 'TSGlobalDeclaration':
        this.withScope(node, () => {
          if (node.body) {
            this.walkReferences(node.body, ancestors.concat(node));
          }
        });
        return;
      case 'TSModuleBlock':
        this.walkChildren(node, ancestors);
        return;
      case 'TSTypeAliasDeclaration':
        this.withScope(node, () => {
          const typeParameters = node.typeParameters ?? node.type_parameters;
          const typeAnnotation = node.typeAnnotation ?? node.type_annotation;
          this.withTypeContext(() => {
            if (typeParameters) {
              this.walkReferences(typeParameters, ancestors.concat(node));
            }
            if (typeAnnotation) {
              this.walkReferences(typeAnnotation, ancestors.concat(node));
            }
          });
        });
        return;
      case 'TSInterfaceDeclaration':
        this.withScope(node, () => {
          const typeParameters = node.typeParameters ?? node.type_parameters;
          this.withTypeContext(() => {
            if (typeParameters) {
              this.walkReferences(typeParameters, ancestors.concat(node));
            }
            if (node.extends) {
              for (const heritage of node.extends ?? []) {
                this.walkReferences(heritage, ancestors.concat(node));
              }
            }
            if (node.body) {
              this.walkReferences(node.body, ancestors.concat(node));
            }
          });
        });
        return;
      case 'TSEnumDeclaration':
        if (node.body) {
          this.walkReferences(node.body, ancestors.concat(node));
        }
        return;
      case 'TSEnumBody':
        this.withScope(node, () => {
          this.walkChildren(node, ancestors);
        });
        return;
      case 'TSEnumMember':
        if (node.initializer) {
          this.walkReferences(node.initializer, ancestors.concat(node));
        }
        return;
      case 'TSMappedType':
        this.withScope(node, () => {
          const nameType = node.nameType ?? node.name_type;
          const typeAnnotation = node.typeAnnotation ?? node.type_annotation;
          this.withTypeContext(() => {
            if (node.constraint) {
              this.walkReferences(node.constraint, ancestors.concat(node));
            }
            if (nameType) {
              this.walkReferences(nameType, ancestors.concat(node));
            }
            if (typeAnnotation) {
              this.walkReferences(typeAnnotation, ancestors.concat(node));
            }
          });
        });
        return;
      case 'TSConditionalType':
        this.withTypeContext(() => {
          const checkType = node.checkType ?? node.check_type;
          const extendsType = node.extendsType ?? node.extends_type;
          const trueType = node.trueType ?? node.true_type;
          const falseType = node.falseType ?? node.false_type;
          if (checkType) {
            this.walkReferences(checkType, ancestors.concat(node));
          }
          this.withScope(node, () => {
            if (extendsType) {
              this.walkReferences(extendsType, ancestors.concat(node));
            }
            if (trueType) {
              this.walkReferences(trueType, ancestors.concat(node));
            }
          });
          if (falseType) {
            this.walkReferences(falseType, ancestors.concat(node));
          }
        });
        return;
      case 'TSFunctionType':
      case 'TSConstructorType':
      case 'TSCallSignatureDeclaration':
      case 'TSConstructSignatureDeclaration':
        this.withScope(node, () => {
          const typeParameters = node.typeParameters ?? node.type_parameters;
          const returnType = node.returnType ?? node.return_type;
          const params = getParamList(node.params);
          this.withTypeContext(() => {
            if (typeParameters) {
              this.walkReferences(typeParameters, ancestors.concat(node));
            }
            for (const param of params) {
              this.walkPatternReferences(param, ancestors.concat(node));
            }
            if (returnType) {
              this.walkReferences(returnType, ancestors.concat(node));
            }
          });
        });
        return;
      case 'TSMethodSignature':
        this.withScope(node, () => {
          const typeParameters = node.typeParameters ?? node.type_parameters;
          const returnType = node.returnType ?? node.return_type;
          const params = getParamList(node.params);
          this.withTypeContext(() => {
            if (node.key && node.computed) {
              this.withValueAsTypeContext(() => {
                this.walkReferences(node.key, ancestors.concat(node));
              });
            }
            if (typeParameters) {
              this.walkReferences(typeParameters, ancestors.concat(node));
            }
            for (const param of params) {
              this.walkPatternReferences(param, ancestors.concat(node));
            }
            if (returnType) {
              this.walkReferences(returnType, ancestors.concat(node));
            }
          });
        });
        return;
      case 'TSPropertySignature':
        this.withTypeContext(() => {
          if (node.key && node.computed) {
            this.withValueAsTypeContext(() => {
              this.walkReferences(node.key, ancestors.concat(node));
            });
          }
          if (node.typeAnnotation ?? node.type_annotation) {
            this.walkReferences(node.typeAnnotation ?? node.type_annotation, ancestors.concat(node));
          }
        });
        return;
      case 'TSTypeQuery':
        if (node.exprName ?? node.expr_name) {
          this.withValueAsTypeContext(() => {
            this.walkReferences(node.exprName ?? node.expr_name, ancestors.concat(node));
          });
        }
        if (node.typeArguments ?? node.type_arguments) {
          this.withTypeContext(() => {
            this.walkReferences(node.typeArguments ?? node.type_arguments, ancestors.concat(node));
          });
        }
        return;
      case 'TSAsExpression':
      case 'TSSatisfiesExpression':
      case 'TSTypeAssertion':
        if (node.expression) {
          this.walkReferences(node.expression, ancestors.concat(node));
        }
        if (node.typeAnnotation ?? node.type_annotation) {
          this.withTypeContext(() => {
            this.walkReferences(node.typeAnnotation ?? node.type_annotation, ancestors.concat(node));
          });
        }
        return;
      case 'TSInstantiationExpression':
        if (node.expression) {
          this.walkReferences(node.expression, ancestors.concat(node));
        }
        if (node.typeArguments ?? node.type_arguments) {
          this.withTypeContext(() => {
            this.walkReferences(node.typeArguments ?? node.type_arguments, ancestors.concat(node));
          });
        }
        return;
      case 'TSNonNullExpression':
        if (node.expression) {
          this.walkReferences(node.expression, ancestors.concat(node));
        }
        return;
      case 'PropertyDefinition':
      case 'ClassProperty':
      case 'AccessorProperty':
      case 'TSAbstractPropertyDefinition':
      case 'TSAbstractAccessorProperty':
        this.walkDecorators(node, ancestors);
        if (node.computed && node.key) {
          this.walkReferences(node.key, ancestors.concat(node));
        }
        if (node.typeAnnotation ?? node.type_annotation) {
          this.withTypeContext(() => {
            this.walkReferences(node.typeAnnotation ?? node.type_annotation, ancestors.concat(node));
          });
        }
        if (node.value) {
          this.walkReferences(node.value, ancestors.concat(node));
        }
        return;
      case 'TSAbstractMethodDefinition':
        // Abstract methods have no body; their `value` is an empty-body
        // function expression. Walk decorators, the computed key, and the
        // signature so any references inside still resolve.
        this.walkDecorators(node, ancestors);
        if (node.computed && node.key) {
          this.walkReferences(node.key, ancestors.concat(node));
        }
        if (node.value) {
          this.walkReferences(node.value, ancestors.concat(node));
        }
        return;
      case 'TSTypePredicate':
        // `x is T` / `asserts x is T`: the parameter name is a value-level
        // reference to the function's parameter, and the optional annotation
        // is a plain type. Use value-as-type for the param so a regular Param
        // binding (not a type binding) can resolve it.
        if (node.parameterName) {
          this.withValueAsTypeContext(() => {
            this.walkReferences(node.parameterName, ancestors.concat(node));
          });
        }
        if (node.typeAnnotation ?? node.type_annotation) {
          this.walkReferences(node.typeAnnotation ?? node.type_annotation, ancestors.concat(node));
        }
        return;
      default:
        break;
    }

    if (node.type === 'JSXIdentifier') {
      const parent = ancestors[ancestors.length - 1];
      const grandparent = ancestors[ancestors.length - 2];
      const parentKey = getParentKey(parent, node);
      if (isJsxIdentifierReference(node, parent, grandparent, parentKey)) {
        this.addReference(node);
      }
      return;
    }

    if (node.type === 'Identifier') {
      const parent = ancestors[ancestors.length - 1];
      const grandparent = ancestors[ancestors.length - 2];
      const parentKey = getParentKey(parent, node);
      if (isIdentifierReference(node, parent, grandparent, parentKey)) {
        this.addReference(node);
      }
      return;
    }

    this.walkChildren(node, ancestors);
  }

  private withScope(node: AnyNode, fn: () => void): void {
    const scopeId = this.scopeIdByNode.get(node);
    if (scopeId == null) {
      fn();
      return;
    }
    this.scopeStack.push({ scopeId });
    fn();
    this.scopeStack.pop();
  }

  private withContext(context: ReferenceContext, fn: () => void): void {
    this.contextStack.push(context);
    fn();
    this.contextStack.pop();
  }

  private withTypeContext(fn: () => void): void {
    this.withContext(ReferenceContext.Type, fn);
  }

  private withValueAsTypeContext(fn: () => void): void {
    this.withContext(ReferenceContext.ValueAsType, fn);
  }

  private currentContext(): ReferenceContext {
    return this.contextStack[this.contextStack.length - 1] ?? ReferenceContext.Value;
  }

  private addReference(node: AnyNode): void {
    const name = node.name;
    const scopeId = this.currentScopeId();
    const bindingId = this.resolveBinding(scopeId, name, this.currentContext());
    const ref: Reference = {
      id: this.references.length,
      name,
      start: node.start ?? 0,
      end: node.end ?? (node.start ?? 0),
      scopeId,
      bindingId,
    };
    this.references.push(ref);
  }

  private currentScopeId(): number {
    return this.scopeStack[this.scopeStack.length - 1]?.scopeId ?? 0;
  }

  private resolveBinding(
    scopeId: number,
    name: string,
    context: ReferenceContext,
  ): number | null {
    let currentScopeId: number | null = scopeId;
    while (currentScopeId != null) {
      const scope: Scope = this.scopes[currentScopeId]!;
      if (context === ReferenceContext.Type) {
        const typeBindingId = scope.typeBindings.get(name);
        if (typeBindingId != null) return typeBindingId;
        const valueBindingId = scope.bindings.get(name);
        if (valueBindingId != null) {
          const bindingKind = this.bindings[valueBindingId]?.kind;
          if (bindingKind && canReferenceAsType(bindingKind)) {
            return valueBindingId;
          }
        }
      } else if (context === ReferenceContext.ValueAsType) {
        const valueBindingId = scope.bindings.get(name);
        if (valueBindingId != null) return valueBindingId;
        const typeBindingId = scope.typeBindings.get(name);
        if (typeBindingId != null) {
          const bindingKind = this.bindings[typeBindingId]?.kind;
          if (bindingKind && canReferenceAsValueAsType(bindingKind)) {
            return typeBindingId;
          }
        }
      } else {
        const bindingId = scope.bindings.get(name);
        if (bindingId != null) return bindingId;
      }
      currentScopeId = scope.parentId;
    }
    return null;
  }

  private walkDecorators(node: AnyNode, ancestors: AnyNode[]): void {
    const decorators = node.decorators;
    if (!Array.isArray(decorators)) return;
    for (const decorator of decorators) {
      if (decorator) {
        this.walkReferences(decorator, ancestors.concat(node));
      }
    }
  }

  private walkPatternReferences(pattern: AnyNode, ancestors: AnyNode[]): void {
    if (!pattern) return;
    // Parameter decorators (e.g. `m(@dec x: number)`) attach to the pattern
    // itself and must resolve against the surrounding scope like any other
    // expression.
    this.walkDecorators(pattern, ancestors);
    if (pattern.type === 'TSParameterProperty' && pattern.parameter) {
      this.walkPatternReferences(pattern.parameter, ancestors.concat(pattern));
      return;
    }
    if (pattern.typeAnnotation) {
      this.withTypeContext(() => {
        this.walkReferences(pattern.typeAnnotation, ancestors.concat(pattern));
      });
    }
    switch (pattern.type) {
      case 'Identifier':
        return;
      case 'RestElement':
        this.walkPatternReferences(pattern.argument, ancestors.concat(pattern));
        return;
      case 'AssignmentPattern':
        this.walkPatternReferences(pattern.left, ancestors.concat(pattern));
        if (pattern.right) {
          this.walkReferences(pattern.right, ancestors.concat(pattern));
        }
        return;
      case 'ArrayPattern':
        for (const element of pattern.elements ?? []) {
          if (element) {
            this.walkPatternReferences(element, ancestors.concat(pattern));
          }
        }
        return;
      case 'ObjectPattern':
        for (const prop of pattern.properties ?? []) {
          if (!prop) continue;
          if (prop.type === 'Property') {
            if (prop.computed && prop.key) {
              this.walkReferences(prop.key, ancestors.concat(prop));
            }
            if (prop.value) {
              this.walkPatternReferences(prop.value, ancestors.concat(prop));
            }
          } else if (prop.type === 'RestElement') {
            this.walkPatternReferences(prop.argument, ancestors.concat(prop));
          }
        }
        return;
      default:
        this.walkReferences(pattern, ancestors.concat(pattern));
    }
  }

  private walkChildren(node: AnyNode, ancestors: AnyNode[]): void {
    const keys = visitorKeys[node.type] ?? [];
    for (const key of keys) {
      const value = node[key];
      if (Array.isArray(value)) {
        for (const child of value) {
          if (isNode(child)) {
            this.walkReferences(child, ancestors.concat(node));
          }
        }
      } else if (isNode(value)) {
        this.walkReferences(value, ancestors.concat(node));
      }
    }
  }
}

function createScope({
  scopes,
  type,
  start,
  end,
  parentId,
  flags,
}: {
  scopes: Scope[];
  type: ScopeType;
  start: number;
  end: number;
  parentId: number | null;
  flags: ScopeFlags;
}): number {
  const scopeId = scopes.length;
  const scope: Scope = {
    id: scopeId,
    type,
    flags,
    start,
    end,
    parentId,
    childIds: [],
    bindings: new Map(),
    typeBindings: new Map(),
  };
  scopes.push(scope);
  if (parentId != null) {
    scopes[parentId].childIds.push(scopeId);
  }
  return scopeId;
}

function inheritStrictMode(flags: ScopeFlags, parentFlags: ScopeFlags): ScopeFlags {
  if (parentFlags & ScopeFlags.StrictMode) {
    return flags | ScopeFlags.StrictMode;
  }
  return flags;
}

function getScopeFlags(type: ScopeType, parentFlags: ScopeFlags): ScopeFlags {
  switch (type) {
    case ScopeType.Program:
      return parentFlags;
    case ScopeType.Function:
      return ScopeFlags.Function;
    case ScopeType.Block:
      return ScopeFlags.Block;
    case ScopeType.Catch:
      return ScopeFlags.Catch | ScopeFlags.Block;
    case ScopeType.Class:
      return ScopeFlags.Class;
    case ScopeType.ClassStaticBlock:
      return ScopeFlags.ClassStaticBlock;
    case ScopeType.For:
      return ScopeFlags.For | ScopeFlags.Block;
    case ScopeType.Switch:
      return ScopeFlags.Switch | ScopeFlags.Block;
    case ScopeType.TsModule:
      return ScopeFlags.TsModuleBlock;
    case ScopeType.Enum:
      return ScopeFlags.Enum;
    case ScopeType.Type:
      return ScopeFlags.Type;
    case ScopeType.TsConditional:
      return ScopeFlags.TsConditional;
    default:
      return ScopeFlags.Block;
  }
}

function getScopeStart(node: AnyNode, type: ScopeType, source: string): number {
  if (type === ScopeType.Program) return 0;
  if (type === ScopeType.TsModule) {
    const body = node.body;
    if (body?.start != null) return body.start;
  }
  if (type === ScopeType.Function) {
    const body = node.body;
    if (body?.start != null) return body.start;
  }
  return node.start ?? 0;
}

function getScopeEnd(node: AnyNode, type: ScopeType, source: string): number {
  if (type === ScopeType.Program) return source.length;
  if (type === ScopeType.TsModule) {
    const body = node.body;
    if (body?.end != null) return body.end;
  }
  if (type === ScopeType.Function) {
    const body = node.body;
    if (body?.end != null) return body.end;
  }
  return node.end ?? source.length;
}

function collectBindingIdentifiers(pattern: AnyNode, out: AnyNode[]): void {
  if (!pattern) return;
  switch (pattern.type) {
    case 'Identifier':
      out.push(pattern);
      return;
    case 'TSParameterProperty':
      collectBindingIdentifiers(pattern.parameter, out);
      return;
    case 'RestElement':
      collectBindingIdentifiers(pattern.argument, out);
      return;
    case 'AssignmentPattern':
      collectBindingIdentifiers(pattern.left, out);
      return;
    case 'ArrayPattern':
      for (const element of pattern.elements ?? []) {
        if (element) collectBindingIdentifiers(element, out);
      }
      return;
    case 'ObjectPattern':
      for (const prop of pattern.properties ?? []) {
        if (!prop) continue;
        if (prop.type === 'Property') {
          collectBindingIdentifiers(prop.value, out);
        } else if (prop.type === 'RestElement') {
          collectBindingIdentifiers(prop.argument, out);
        }
      }
      return;
    default:
      return;
  }
}

function getParentKey(parent: AnyNode | undefined, node: AnyNode): string | null {
  if (!parent) return null;
  for (const key of Object.keys(parent)) {
    const value = parent[key];
    if (value === node) return key;
    if (Array.isArray(value)) {
      if (value.includes(node)) return key;
    }
  }
  return null;
}

function isIdentifierReference(
  node: AnyNode,
  parent?: AnyNode,
  grandparent?: AnyNode,
  parentKey?: string | null,
): boolean {
  if (!parent) return true;

  if (
    parent.type === 'MemberExpression' &&
    parentKey === 'property' &&
    parent.computed === false
  ) {
    return false;
  }

  if (
    parent.type === 'Property' &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }

  if (
    parent.type === 'MethodDefinition' &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }

  if (
    parent.type === 'PropertyDefinition' &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }
  if (
    parent.type === 'ClassProperty' &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }
  if (
    parent.type === 'AccessorProperty' &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }
  if (
    (parent.type === 'TSAbstractMethodDefinition' ||
      parent.type === 'TSAbstractPropertyDefinition' ||
      parent.type === 'TSAbstractAccessorProperty') &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }
  if (
    (parent.type === 'TSPropertySignature' || parent.type === 'TSMethodSignature') &&
    parentKey === 'key' &&
    parent.computed === false
  ) {
    return false;
  }

  // Note: we don't add an ObjectPattern-specific exclusion. Declaration
  // contexts (VariableDeclarator, params, catch) route through
  // `walkPatternReferences` which never calls `isIdentifierReference`, so the
  // only time a `Property` inside an `ObjectPattern` reaches this check is
  // when the pattern is an *assignment target* — in which case the shorthand
  // value identifier genuinely is a reference. The general Property.key rule
  // above still excludes the non-computed key side.

  if (
    parent.type === 'VariableDeclarator' &&
    parentKey === 'id'
  ) {
    return false;
  }

  if (
    (parent.type === 'FunctionDeclaration' ||
      parent.type === 'FunctionExpression' ||
      parent.type === 'ArrowFunctionExpression') &&
    (parentKey === 'id' || parentKey === 'params')
  ) {
    return false;
  }

  if (
    (parent.type === 'ClassDeclaration' || parent.type === 'ClassExpression') &&
    parentKey === 'id'
  ) {
    return false;
  }
  if (
    (parent.type === 'TSTypeAliasDeclaration' ||
      parent.type === 'TSInterfaceDeclaration' ||
      parent.type === 'TSEnumDeclaration' ||
      parent.type === 'TSModuleDeclaration' ||
      parent.type === 'TSImportEqualsDeclaration') &&
    parentKey === 'id'
  ) {
    return false;
  }
  if (parent.type === 'TSEnumMember' && parentKey === 'id') {
    return false;
  }
  if (parent.type === 'TSTypeParameter' && parentKey === 'name') {
    return false;
  }
  if (parent.type === 'TSMappedType' && parentKey === 'key') {
    return false;
  }
  if (parent.type === 'TSIndexSignature' && parentKey === 'parameters') {
    return false;
  }
  if (
    (parent.type === 'TSQualifiedName' || parent.type === 'TSImportTypeQualifiedName') &&
    parentKey === 'right'
  ) {
    return false;
  }

  if (
    (parent.type === 'ImportSpecifier' ||
      parent.type === 'ImportDefaultSpecifier' ||
      parent.type === 'ImportNamespaceSpecifier') &&
    parentKey === 'local'
  ) {
    return false;
  }

  if (parent.type === 'CatchClause' && parentKey === 'param') {
    return false;
  }

  if (parent.type === 'LabeledStatement' && parentKey === 'label') {
    return false;
  }
  if (
    (parent.type === 'BreakStatement' || parent.type === 'ContinueStatement') &&
    parentKey === 'label'
  ) {
    return false;
  }

  return true;
}

function isJsxIdentifierReference(
  node: AnyNode,
  parent?: AnyNode,
  grandparent?: AnyNode,
  parentKey?: string | null,
): boolean {
  if (!parent) return true;
  if (parent.type === 'JSXAttribute' && parentKey === 'name') {
    return false;
  }
  if (parent.type === 'JSXMemberExpression' && parentKey === 'property') {
    return false;
  }
  if (parent.type === 'JSXNamespacedName') {
    return false;
  }
  return true;
}
